/**
 * @summary Download PDF report
 */
export const getGetReportPdfUrl = (productId: number) => {
  return `/api/reports/${productId}/pdf`;
};

export const getReportPdf = async (
  productId: number,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getGetReportPdfUrl(productId), {
    ...options,
    method: "GET",
  });
};

export const getGetReportPdfQueryKey = (productId: number) => {
  return [`/api/reports/${productId}/pdf`] as const;
};

export const getGetReportPdfQueryOptions = <
  TData = Awaited<ReturnType<typeof getReportPdf>>,
  TError = ErrorType<unknown>,
>(
  productId: number,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getReportPdf>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetReportPdfQueryKey(productId);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getReportPdf>>> = ({
    signal,
  }) => getReportPdf(productId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!productId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getReportPdf>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetReportPdfQueryResult = NonNullable<
  Awaited<ReturnType<typeof getReportPdf>>
>;
export type GetReportPdfQueryError = ErrorType<unknown>;

